VALUES
  ('judicial-57112235-moex-00577', 'judicial-57112235', 'judicial-57112235-moex-111-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '依據我國監獄行刑法之規定，子女隨母入監最多至滿3歲為止，但經社會福利主管機關評估，認 在監符合子女最佳利益者，最多得延長在監安置期間至子女滿多久為止？', '["3歲4個月", "3歲6個月", "3歲8個月", "3歲10個月"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "726b27a1a90d", "answer_pdf_sha1": "a7721ff1b3e7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00578', 'judicial-57112235', 'judicial-57112235-moex-111-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '有關監獄戒護勤務的執行，下列敘述何者錯誤？', '["經常性勤務係指監獄戒護人員，每日定時定式執行之勤務，如工場、舍房、崗哨、巡邏等工作", "特別勤務係指監獄戒護人員於天災事變，如火災、地震、颱風等事故或偶發戒護事故發生，臨 時編組之緊急應變勤務", "夜間勤務係指戒護人員於晚上收封期間，配合監獄警備需要所執行之勤務，如夜間巡邏、門衛 等勤務", "警備勤務係指戒護人員直接涉及受刑人生活管理及性行考核，維持監獄秩序並協助各項業務推 展所執行之勤務，如工場、舍房、炊場等勤務"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "726b27a1a90d", "answer_pdf_sha1": "a7721ff1b3e7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00579', 'judicial-57112235', 'judicial-57112235-moex-111-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '當代矯正機構經營管理模式中，加州共識模式（ConsensualModel）的特性，下列敘述何者正確？', '["採BT制度，即受刑人管理受刑人，以協助管理人員處理各項勤務", "採半軍事化的組織型態，強調嚴明紀律與服從性，工作與教育並重的矯正模式", "處遇內容採嚴密的調查分類程序，及設立處理受刑人申訴專責機構，以達到公平與公正的管理 模式", "倡導受刑人應對其行為負責，強調人道立場少干預受刑人 20720"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "726b27a1a90d", "answer_pdf_sha1": "a7721ff1b3e7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00580', 'judicial-57112235', 'judicial-57112235-moex-111-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '團體生活須有共同之行為規範，有關受刑人次級文化之敘述，下列何者錯誤？', '["可協助受刑人定位自我角色", "用以劃分與管教人員所持價值觀之不同", "有助於受刑人次級文化之整合", "因資訊發達與交流迅速之故，各機構間之次級文化已無差異"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "726b27a1a90d", "answer_pdf_sha1": "a7721ff1b3e7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00581', 'judicial-57112235', 'judicial-57112235-moex-111-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '有關戒護安全武器管理原則，下列敘述何者錯誤？', '["監獄應設專用槍械庫，所有械彈應分門別類儲放", "槍械庫應遠離收容人之舍房或活動之範圍", "槍械庫應指定專人負責管理", "槍械庫應嚴密管制，槍械管理人員每週檢查1次，戒護科長每月檢查1次，典獄長每季檢查1次"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "726b27a1a90d", "answer_pdf_sha1": "a7721ff1b3e7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00582', 'judicial-57112235', 'judicial-57112235-moex-111-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '矯正機關四八制的戒護勤務制度特性，下列何者錯誤？', '["每班次勤四息八，能顧及睡眠不致過勞", "每一崗位由3人或4人輪流，工作負荷不重，合於勞逸平均原則", "每日勤務時間固定，時間明確，責任分明", "在戒護人力少之矯正機關，較容易實施"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "726b27a1a90d", "answer_pdf_sha1": "a7721ff1b3e7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00583', 'judicial-57112235', 'judicial-57112235-moex-111-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '有關監獄受刑人之權益問題，下列敘述何者正確？', '["受刑人人權與監獄戒護管理兩者間應取得平衡", "我國目前尚未有完備的受刑人申訴制度", "我國受刑人尚無宗教自由權之保障", "我國受刑人均有公民參政權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "726b27a1a90d", "answer_pdf_sha1": "a7721ff1b3e7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00584', 'judicial-57112235', 'judicial-57112235-moex-111-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '學者Flanagan（1990）指出長刑期受刑人的主要特徵，下列何者錯誤？', '["容易與外界關係斷絕", "容易認同短刑期受刑人之觀點", "普遍有老化、心有餘力不足之情形", "偏好穩定的服刑環境"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "726b27a1a90d", "answer_pdf_sha1": "a7721ff1b3e7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00585', 'judicial-57112235', 'judicial-57112235-moex-111-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '有關監獄脫逃事故之防範對策，下列敘述何者錯誤？', '["利用受刑人掌控囚情動態", "不使收容人脫離視線", "確實掌握收容人數", "工場舍房確實上鎖"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "726b27a1a90d", "answer_pdf_sha1": "a7721ff1b3e7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00586', 'judicial-57112235', 'judicial-57112235-moex-111-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '有關監獄暴行之敘述，下列何者錯誤？', '["監獄暴行之跡象只能從受刑人實際衝突的言語或行為觀察，無法單就請求換房、轉配業或要求 單人居住查覺", "監獄暴行可能讓受刑人趨於消極，如恐懼、憤怒、憂鬱、或面臨精神疾病之壓力", "部分受刑人會以加入監獄幫派以尋求庇護", "監獄暴行除發生於受刑人與受刑人之間暴行外，亦可能發生於對管理人員施暴或誣陷濫告以達 成其獲得利益之目的"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "726b27a1a90d", "answer_pdf_sha1": "a7721ff1b3e7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL)
